@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

@* Step Indicator Bar *@
<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <div class="step @stepClass" @onclick="() => NavigateToStep(stepIndex)">
            <div class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[stepIndex]</div>
        </div>
        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector"></div>
        }
    }
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger mt-3">@ErrorMessage</div>
}

@* Step Content *@
<div class="step-content mt-4">
    @switch (CurrentStep)
    {
        case 0:
            @* Step 1 — Personal Info *@
            <h3>Personal Information</h3>
            <div class="mb-3">
                <label class="form-label">Full Name *</label>
                <input type="text" class="form-control" @bind="FullName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email *</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone *</label>
                <input type="tel" class="form-control" @bind="Phone" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address *</label>
                <input type="text" class="form-control" @bind="Address" />
            </div>
            <div class="d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@IsLoading">
                    @if (IsLoading) { <span>Validating...</span> } else { <span>Next</span> }
                </button>
            </div>
            break;

        case 1:
            @* Step 2 — Work History *@
            <h3>Work History</h3>
            @for (int i = 0; i < WorkEntries.Count; i++)
            {
                var index = i;
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5>Position @(index + 1)</h5>
                        @if (WorkEntries.Count > 1)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                        }
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Company Name *</label>
                        <input type="text" class="form-control" @bind="WorkEntries[index].Company" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Job Title *</label>
                        <input type="text" class="form-control" @bind="WorkEntries[index].Title" />
                    </div>
                    <div class="row mb-2">
                        <div class="col-md-6">
                            <label class="form-label">Start Date *</label>
                            <input type="date" class="form-control" @bind="WorkEntries[index].StartDate" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">End Date</label>
                            <input type="date" class="form-control" @bind="WorkEntries[index].EndDate" disabled="@WorkEntries[index].IsCurrent" />
                            <div class="form-check mt-1">
                                <input type="checkbox" class="form-check-input" id="current-@index" @bind="WorkEntries[index].IsCurrent" />
                                <label class="form-check-label" for="current-@index">Currently working here</label>
                            </div>
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <textarea class="form-control" rows="3" @bind="WorkEntries[index].Description"></textarea>
                    </div>
                </div>
            }
            <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
            </div>
            break;

        case 2:
            @* Step 3 — References *@
            <h3>References</h3>
            @for (int i = 0; i < References.Count; i++)
            {
                var index = i;
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center mb-2">
                        <h5>Reference @(index + 1)</h5>
                        @if (References.Count > 2)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
                        }
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Name *</label>
                        <input type="text" class="form-control" @bind="References[index].Name" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Relationship *</label>
                        <input type="text" class="form-control" @bind="References[index].Relationship" />
                    </div>
                    <div class="row mb-2">
                        <div class="col-md-6">
                            <label class="form-label">Email *</label>
                            <input type="email" class="form-control" @bind="References[index].Email" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Phone *</label>
                            <input type="tel" class="form-control" @bind="References[index].Phone" />
                        </div>
                    </div>
                </div>
            }
            @if (References.Count < 3)
            {
                <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
            </div>
            break;

        case 3:
            @* Step 4 — Cover Letter *@
            <h3>Cover Letter</h3>
            <div class="mb-3">
                <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput" maxlength="2000"></textarea>
                <div class="form-text text-end">@CoverLetter.Length / 2000 characters</div>
            </div>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
            </div>
            break;

        case 4:
            @* Step 5 — Review & Submit *@
            @if (IsSubmitted)
            {
                <div class="alert alert-success">
                    <h4>Application Submitted Successfully!</h4>
                    <p>Your application ID is: <strong>@ApplicationId</strong></p>
                </div>
            }
            else
            {
                <h3>Review & Submit</h3>

                @* Personal Info Section *@
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Personal Information</h5>
                        <a href="javascript:void(0)" @onclick="() => GoToStep(0)">Edit</a>
                    </div>
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Full Name</dt>
                        <dd class="col-sm-9">@FullName</dd>
                        <dt class="col-sm-3">Email</dt>
                        <dd class="col-sm-9">@Email</dd>
                        <dt class="col-sm-3">Phone</dt>
                        <dd class="col-sm-9">@Phone</dd>
                        <dt class="col-sm-3">Address</dt>
                        <dd class="col-sm-9">@Address</dd>
                    </dl>
                </div>

                @* Work History Section *@
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <a href="javascript:void(0)" @onclick="() => GoToStep(1)">Edit</a>
                    </div>
                    @foreach (var entry in WorkEntries)
                    {
                        <div class="border-bottom pb-2 mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small>@entry.StartDate.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))</small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References Section *@
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <a href="javascript:void(0)" @onclick="() => GoToStep(2)">Edit</a>
                    </div>
                    @foreach (var reference in References)
                    {
                        <div class="border-bottom pb-2 mb-2">
                            <strong>@reference.Name</strong> (@reference.Relationship)<br />
                            <small>@reference.Email | @reference.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter Section *@
                <div class="card mb-3 p-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <a href="javascript:void(0)" @onclick="() => GoToStep(3)">Edit</a>
                    </div>
                    <p style="white-space: pre-wrap;">@CoverLetter</p>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@IsLoading">
                        @if (IsLoading) { <span>Submitting...</span> } else { <span>Submit Application</span> }
                    </button>
                </div>
            }
            break;
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int CurrentStep { get; set; }
    private bool IsLoading { get; set; }
    private bool IsSubmitted { get; set; }
    private int ApplicationId { get; set; }
    private string ErrorMessage { get; set; } = string.Empty;

    // Step 1 fields
    private string FullName { get; set; } = string.Empty;
    private string Email { get; set; } = string.Empty;
    private string Phone { get; set; } = string.Empty;
    private string Address { get; set; } = string.Empty;

    // Step 2 fields
    private List<WorkEntryModel> WorkEntries { get; set; } = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> References { get; set; } = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 fields
    private string CoverLetter { get; set; } = string.Empty;

    private string GetStepClass(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < CurrentStep) return "completed";
        return "dimmed";
    }

    private void NavigateToStep(int step)
    {
        if (step < CurrentStep && !IsSubmitted)
        {
            CurrentStep = step;
            ErrorMessage = string.Empty;
        }
    }

    private void GoToStep(int step)
    {
        CurrentStep = step;
        ErrorMessage = string.Empty;
    }

    private void Back()
    {
        if (CurrentStep > 0)
        {
            CurrentStep--;
            ErrorMessage = string.Empty;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        ErrorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email) ||
            string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsLoading = true;
        try
        {
            var isValidEmail = await ApplicationService.ValidateEmailAsync(Email);
            if (!isValidEmail)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
            CurrentStep++;
        }
        finally
        {
            IsLoading = false;
        }
    }

    private void NextFromWorkHistory()
    {
        ErrorMessage = string.Empty;

        foreach (var entry in WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default)
            {
                ErrorMessage = "Company, job title, and start date are required for all entries.";
                return;
            }
        }

        CurrentStep++;
    }

    private void NextFromReferences()
    {
        ErrorMessage = string.Empty;

        foreach (var reference in References)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
                string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        CurrentStep++;
    }

    private void NextFromCoverLetter()
    {
        ErrorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "Cover letter is required.";
            return;
        }

        CurrentStep++;
    }

    private void AddWorkEntry() => WorkEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (WorkEntries.Count > 1)
            WorkEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        IsLoading = true;
        ErrorMessage = string.Empty;

        try
        {
            var personal = new PersonalInfo(FullName, Email, Phone, Address);
            var workHistory = new WorkHistory(WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? string.Empty)
            ).ToList());
            var references = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
            ).ToList();
            var application = new JobApplication(personal, workHistory, references, CoverLetter);

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsLoading = false;
        }
    }

    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

