.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 1.5rem 0;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background-color: #f8f9fa;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    background-color: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.step.completed .step-circle {
    background-color: #198754;
    border-color: #198754;
    color: white;
}

.step.dimmed .step-circle {
    opacity: 0.5;
}

.step-label {
    font-size: 0.75rem;
    margin-top: 0.3rem;
    text-align: center;
    color: #6c757d;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.dimmed .step-label {
    opacity: 0.5;
}

.step-connector {
    flex: 1;
    height: 2px;
    background-color: #dee2e6;
    min-width: 20px;
    max-width: 60px;
    align-self: center;
    margin-bottom: 1.2rem;
}

.step-content {
    max-width: 800px;
    margin: 0 auto;
}

